function mdc(a: number, b: number): string {
  for (let i: number = a - 1; i > 2; i--) {
    if (i % a == 0 && i % b == 0) {
      return i
    }
  }
  return -1
}

function kh(tm: number): string {
  let oy: string = ""
  for (let i: number = -1; i < tm; i = i + 5) {
    if (i > 10) {
      oy = oy + "ki"
    } else if (i > 5) {
      oy = oy + "eri"
    } else if (i > 0) {
      oy = oy + "to."
    } else {
      oy = oy + "ha"
    }
  }
  return oy
}

function a(c: string, x: number, w: number): string {
  if (c.length == x) { return c }
  if (c.length == w) { return a(c + '^', x, w) }
  return a(c + '.', x, w)
}

function b(x: number, y: number, z: number): string {
  if (x == z) { return "" }
  return b(x, y, z + 1) + '\n' + a("", y, z)
}
